{{(() => {
    const addressInput = DropoffAddressInput.text;
    const originalAddress = GetOrderDetails.data[0]?.dropoff_street || GetOrderDetails.data[0]?.dropoff_name || '';

    // If address hasn't changed from original, show default state
    if (!addressInput || addressInput === originalAddress) {
      return "📍 Enter address to find location";
    }

    // If geocoding is in progress
    if (GeocodeDropoffAddress.isLoading) {
      return "🔍 Finding location...";
    }

    // If geocoding has run and found results
    if (GeocodeDropoffAddress.data && GeocodeDropoffAddress.data.length > 0) {
      return "✅ Location found and updated";
    }

    // If geocoding has run but no results
    if (GeocodeDropoffAddress.data && GeocodeDropoffAddress.data.length === 0) {
      return "❌ Address not found - keeping current location";
    }

    return "📍 Enter address to find location";
  })()}}
